import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, Cpu, Zap } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading]   = useState(false);
  const [focused, setFocused]   = useState(null);

  const { login } = useAuth();
  const navigate  = useNavigate();

  const [scanKey, setScanKey] = useState(0);
  useEffect(() => { setScanKey(k => k + 1); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter your credentials.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard');
    } catch {
      toast.error('Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    /* Full viewport, flex-centered, generous padding on all sides */
    <div style={{
      minHeight: '100vh',
      width: '100%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '3rem 1.5rem',           /* ← central padding */
      boxSizing: 'border-box',
      background: `radial-gradient(circle at center, var(--bg-secondary) 0%, var(--bg-main) 75%)`,
      position: 'relative',
    }}>

      {/* Fixed ambient glows — out of flow */}
      <div aria-hidden="true" style={{
        position: 'fixed', top: '-100px', left: '-100px',
        width: '350px', height: '350px',
        background: 'var(--accent-glow)', borderRadius: '50%',
        filter: 'blur(90px)', opacity: 0.55, pointerEvents: 'none', zIndex: 0,
      }} />
      <div aria-hidden="true" style={{
        position: 'fixed', bottom: '-80px', right: '-80px',
        width: '280px', height: '280px',
        background: 'var(--accent-glow)', borderRadius: '50%',
        filter: 'blur(100px)', opacity: 0.3, pointerEvents: 'none', zIndex: 0,
      }} />

      {/* ── Compact Login Card ── */}
      <div
        className="reveal-node"
        style={{
          position: 'relative',
          zIndex: 1,
          width: '100%',
          maxWidth: '360px',            /* ← small box */
          padding: '2.25rem 2rem',      /* ← inner padding */
          borderRadius: '24px',
          backdropFilter: 'blur(24px)',
          WebkitBackdropFilter: 'blur(24px)',
          background: 'var(--surface-glass)',
          border: '1px solid var(--surface-border)',
          boxShadow: 'var(--shadow-elevated)',
          overflow: 'hidden',
          transition: 'box-shadow 0.4s ease, border-color 0.4s ease',
        }}
        onMouseEnter={e => {
          e.currentTarget.style.boxShadow = `0 0 40px var(--accent-glow), var(--shadow-elevated)`;
          e.currentTarget.style.borderColor = 'var(--accent-primary)';
        }}
        onMouseLeave={e => {
          e.currentTarget.style.boxShadow = 'var(--shadow-elevated)';
          e.currentTarget.style.borderColor = 'var(--surface-border)';
        }}
      >
        {/* Laser scan */}
        <span key={scanKey} className="animate-laser" aria-hidden="true" />

        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
          <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '0.875rem' }}>
            <div style={{
              width: '48px', height: '48px', borderRadius: '14px',
              background: 'var(--accent-muted)',
              border: '1px solid var(--accent-primary)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              boxShadow: '0 0 20px var(--accent-glow)',
            }}>
              <Cpu size={22} color="var(--accent-primary)" />
            </div>
          </div>
          <h1 style={{
            fontSize: '1.5rem', fontWeight: 300,
            letterSpacing: '-0.02em',
            color: 'var(--text-primary)',
            margin: '0 0 0.35rem',
          }}>
            Welcome Back
          </h1>
          <p style={{
            fontSize: '0.6rem', textTransform: 'uppercase',
            letterSpacing: '0.22em', color: 'var(--text-muted)', margin: 0,
          }}>
            Sign in to access your node
          </p>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>

          {/* Email */}
          <div>
            <label htmlFor="login-email" style={{
              display: 'block', fontSize: '0.6rem', fontWeight: 700,
              textTransform: 'uppercase', letterSpacing: '0.18em',
              color: focused === 'email' ? 'var(--accent-primary)' : 'var(--text-muted)',
              marginBottom: '0.4rem', transition: 'color 0.2s ease',
            }}>
              Email Address
            </label>
            <input
              id="login-email"
              type="email"
              placeholder="operator@finify.ai"
              value={email}
              onChange={e => setEmail(e.target.value)}
              onFocus={() => setFocused('email')}
              onBlur={() => setFocused(null)}
              className="cyber-input"
              autoComplete="email"
              required
            />
          </div>

          {/* Password */}
          <div>
            <label htmlFor="login-password" style={{
              display: 'block', fontSize: '0.6rem', fontWeight: 700,
              textTransform: 'uppercase', letterSpacing: '0.18em',
              color: focused === 'password' ? 'var(--accent-primary)' : 'var(--text-muted)',
              marginBottom: '0.4rem', transition: 'color 0.2s ease',
            }}>
              Master Key
            </label>
            <div style={{ position: 'relative' }}>
              <input
                id="login-password"
                type={showPass ? 'text' : 'password'}
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
                onFocus={() => setFocused('password')}
                onBlur={() => setFocused(null)}
                className="cyber-input"
                style={{ paddingRight: '3rem' }}
                autoComplete="current-password"
                required
              />
              <button
                type="button"
                onClick={() => setShowPass(v => !v)}
                aria-label={showPass ? 'Hide password' : 'Show password'}
                style={{
                  position: 'absolute', right: '0.875rem', top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none', border: 'none', padding: 0,
                  cursor: 'pointer', color: 'var(--text-muted)',
                  display: 'flex', alignItems: 'center',
                  transition: 'color 0.2s ease',
                }}
                onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
                onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
              >
                {showPass ? <EyeOff size={15} /> : <Eye size={15} />}
              </button>
            </div>
          </div>

          {/* Forgot */}
          <div style={{ textAlign: 'right', marginTop: '-0.25rem' }}>
            <Link to="/forgot-password" style={{
              fontSize: '0.6rem', textTransform: 'uppercase',
              letterSpacing: '0.15em', color: 'var(--text-muted)',
              textDecoration: 'none', transition: 'color 0.2s ease',
            }}
              onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
              onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
            >
              Forgot key?
            </Link>
          </div>

          {/* Submit */}
          <button
            type="submit"
            className="cyber-btn"
            disabled={loading}
            style={{ marginTop: '0.25rem' }}
          >
            {loading
              ? <><Zap size={13} style={{ animation: 'pulse 1s ease-in-out infinite' }} /> SYNCHRONIZING...</>
              : 'Access Node'
            }
          </button>
        </form>

        {/* Footer */}
        <div style={{
          marginTop: '1.5rem',
          paddingTop: '1.25rem',
          borderTop: '1px solid var(--surface-border)',
          textAlign: 'center',
        }}>
          <p style={{
            fontSize: '0.6rem', textTransform: 'uppercase',
            letterSpacing: '0.2em', color: 'var(--text-muted)', margin: 0,
          }}>
            No account?{' '}
            <Link to="/register" style={{
              color: 'var(--accent-primary)', textDecoration: 'none',
              fontWeight: 700, transition: 'opacity 0.2s ease',
            }}
              onMouseEnter={e => e.currentTarget.style.opacity = '0.7'}
              onMouseLeave={e => e.currentTarget.style.opacity = '1'}
            >
              Create one
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
